function AssignmentList({ assignments, setAssignments, setMessage }) {
  const deleteAssignment = async (id) => {
    const confirmDelete = window.confirm("⚠️ Are you sure you want to delete this assignment?");
    if (!confirmDelete) return;

    try {
      const response = await fetch(`http://localhost:8080/assignments/delete/${id}`, { method: "DELETE" });
      if (response.ok) {
        setAssignments(prev => prev.filter(a => a.id !== id));
        setMessage("✅ Assignment deleted successfully!");
        setTimeout(() => setMessage(""), 3000);
      }
    } catch (error) {
      console.error(error);
    }
  };

  const submitAssignment = async (id) => {
    try {
      const response = await fetch(`http://localhost:8080/assignments/submit/${id}`, { method: "PUT" });
      if (response.ok) {
        setAssignments(prev =>
          prev.map(a => (a.id === id ? { ...a, status: "Submitted" } : a))
        );
        setMessage("✅ Assignment submitted successfully!");
        setTimeout(() => setMessage(""), 3000);
      }
    } catch (error) {
      console.error(error);
    }
  };

  if (!Array.isArray(assignments)) return <p>Loading assignments...</p>;

  return (
    <div className="card">
      <h2>Assignments</h2>
      <ul>
        <li className="assignment-header">
          <span>Title</span>
          <span>Subject</span>
          <span>Due Date</span>
          <span>Status</span>
          <span>Action</span>
        </li>

        {assignments.map((assignment) => (
          <li key={assignment.id}>
            <span>{assignment.title}</span>
            <span>{assignment.subject}</span>
            <span>{assignment.dueDate}</span>
            <span className={`status ${assignment.status === "Pending" ? "pending" : "submitted"}`}>
              {assignment.status}
            </span>
            <span>
              {assignment.status === "Pending" && (
                <button onClick={() => submitAssignment(assignment.id)}>Submit</button>
              )}
              <button style={{ backgroundColor: "#ef4444", marginLeft: "8px" }} onClick={() => deleteAssignment(assignment.id)}>Delete</button>
            </span>
          </li>
        ))}
      </ul>
    </div>
  );
}
